#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    long long data;
    struct Node* next;
} Node;

Node* createNode(long long x){
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = x;
    n->next = NULL;
    return n;
}

Node* reverseList(Node* head){
    Node *prev = NULL, *curr = head, *next = NULL;
    while(curr){
        next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        Node *head = NULL, *tail = NULL;
        long long x;
        while(scanf("%lld", &x)==1 && x!=-1){
            Node* nd = createNode(x);
            if(!head) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        head = reverseList(head);
        for(Node* p=head; p; p=p->next) printf("%lld ", p->data);
        printf("-1\n");
        while(head){ Node* tmp=head; head=head->next; free(tmp); }
    }
    return 0;
}

